import{_ as i,c as l,o,ag as f}from"./chunks/framework.DPDPlp3K.js";const p=JSON.parse('{"title":"Office的安装","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/Windows/MicrosoftOffice.md","filePath":"计算机/Windows/MicrosoftOffice.md","lastUpdated":null}'),r={name:"计算机/Windows/MicrosoftOffice.md"};function t(a,e,c,n,s,u){return o(),l("div",null,e[0]||(e[0]=[f('<h1 id="office的安装" tabindex="-1">Office的安装 <a class="header-anchor" href="#office的安装" aria-label="Permalink to &quot;Office的安装&quot;">​</a></h1><ul><li>现在新买的个人笔记本电脑, 预装的 Windows 系统一般都会附赠家庭版 Office, 激活系统过程中注册好微软账号, 首次打开 Office 就能领取到微软账户.</li><li>查询自己有没有正版 Office：个人用户 <a href="https://account.microsoft.com/services/" target="_blank" rel="noreferrer">&gt;&gt;点击这里检查&lt;&lt;</a>，企业用户 <a href="https://portal.office.com/account/?ref=MeControl#subscriptions" target="_blank" rel="noreferrer">&gt;&gt;点击这里检查&lt;&lt;</a>。</li><li>但家庭版 Office 只有办公三件套. 想要获得其它 Office 软件还需要手动安装.</li><li>最方便的、最安全的方式是使用 <a href="https://learn.microsoft.com/zh-cn/microsoft-365-apps/deploy/overview-office-deployment-tool" target="_blank" rel="noreferrer">Office 部署工具(OTD)</a>，ODT 是一种微软官方提供的命令行工具，可用于下载 Microsoft 365 应用并将其部署到客户端计算机。</li></ul><h2 id="office-tool-plus" tabindex="-1">Office Tool Plus <a class="header-anchor" href="#office-tool-plus" aria-label="Permalink to &quot;Office Tool Plus&quot;">​</a></h2><ul><li>Office Tool Plus 是第三方的工具，基于 Office 部署工具 (ODT) 打造，可以很轻松地部署 Office。</li><li>并且 Office Tool Plus 可以为您安装密钥或者配置 KMS 服务，从而激活 office</li><li>#免费 #开源</li><li>支持下列产品： <ul><li>Microsoft 365</li><li>Office 2016 - 2024</li><li>Visio Online Plan 2 &amp; Visio 2016 - 2024</li><li>Project Online Desktop Client &amp; Project 2016 - 2024</li></ul></li><li>官网：<a href="https://otp.landian.vip/zh-cn/" target="_blank" rel="noreferrer">Office Tool Plus | 一键部署 Office (landian.vip)</a></li><li>文档：<a href="https://www.coolhub.top/archives/42" target="_blank" rel="noreferrer">新手必读 Office Tool Plus 入门教程 - Yerong の小窝 (coolhub.top)</a></li></ul><h2 id="office-各种版本选择" tabindex="-1">Office 各种版本选择 <a class="header-anchor" href="#office-各种版本选择" aria-label="Permalink to &quot;Office 各种版本选择&quot;">​</a></h2><ul><li>Retail版和Volume版： <ul><li><strong>Retail版</strong>：零售版是面向个人消费者设计的，通常通过商店购买，每个产品密钥只能激活一台设备。零售版的密钥只能用于单机激活，不能用于批量激活。</li><li><strong>Volume版</strong>：批量授权版是为企业客户设计的，适用于需要批量部署的场景。一个密钥可以激活多台设备，且无需转换即可使用 <strong>KMS</strong>（Key Management Service）进行激活。</li></ul></li></ul><p>因此想要免费激活请选择带”批量许可证“标签.</p><ul><li>LTSC版（Long-Term Servicing Channel）：是一种长期服务通道版本，专为商业和政府客户设计。这个版本的特点是提供一次性购买的永久授权，不需要定期更新，适合在无法连接互联网或需要长期稳定环境的设备上使用.</li></ul><div class="warning custom-block"><p class="custom-block-title">注意事项</p><p>1.Office, Visio 和 Project 三个产品的授权是可以分开处理的，所以你不必担心搞 Visio 会影响 Office. 2.不能使用 KMS 激活零售 (Retail) 许可证，KMS 只能激活批量 (Volume) 许可证.</p></div><h2 id="免费使用-office-2010" tabindex="-1">免费使用 office 2010 <a class="header-anchor" href="#免费使用-office-2010" aria-label="Permalink to &quot;免费使用 office 2010&quot;">​</a></h2><ul><li><a href="https://www.freedidi.com/11501.html" target="_blank" rel="noreferrer">免费使用 Office 办公软件！支持XP、 win7、8、10、11</a></li></ul><h2 id="office的替代" tabindex="-1">office的替代 <a class="header-anchor" href="#office的替代" aria-label="Permalink to &quot;office的替代&quot;">​</a></h2><ul><li>免费开源的办公软件有: libreoffice, onlyoffice</li><li>LibreOffice是最接近office365的开源软件</li><li>#免费 #开源 #跨平台</li><li>官网: <a href="https://zh-cn.libreoffice.org/" target="_blank" rel="noreferrer">LibreOffice</a></li></ul>',13)]))}const d=i(r,[["render",t]]);export{p as __pageData,d as default};
